module adder_16bit(
    input [15:0] a,
    input [15:0] b,
    input cin,
    output [15:0] sum,
    output cout
);

wire [15:0] sum;
wire [15:0] carry;

assign carry[0] = cin;
assign {co, sum[15]} = a[15] + b[15] + carry[15];

genvar i;
generate
    for (i = 0; i < 15; i = i + 1) begin
        assign {carry[i+1], sum[i]} = a[i] + b[i] + carry[i];
    end
endgenerate

assign y = sum;

endmodule
